const results = [];

// Loop through the raw ClickUp payload
for (const item of $input.all()) {
  const task = item.json;

  // 1. Extract Budget (ClickUp hides this inside a custom_fields array)
  let budget = 0;
  if (task.custom_fields) {
    const budgetField = task.custom_fields.find(f => f.name === "Budget Hours");
    if (budgetField && budgetField.value) {
      budget = parseFloat(budgetField.value);
    }
  }

  // 2. Extract Time Tracked (ClickUp returns this in milliseconds. We need hours.)
  const timeTrackedMs = parseInt(task.time_spent) || 0;
  const timeTrackedHours = timeTrackedMs / 3600000;

  // 3. Rebuild a clean JSON object
  results.push({
    json: {
      task_id: task.id,
      task_name: task.name,
      budget_hours: budget,
      tracked_hours: parseFloat(timeTrackedHours.toFixed(2))
    }
  });
}

return results;

// 1. Grab data from the previous nodes
// We use n8n's $items() method to fetch the ClickUp payload, ignoring the DB overwrite
const clickupTasks = $items("[TRANSFORM] Normalize_Payload").map(item => item.json);
const dbStates = $input.all().map(item => item.json);

const results = [];

for (const task of clickupTasks) {
    // 2. Find the previous state in the DB (Defaults to "NEW" if not found)
    const dbRecord = dbStates.find(r => r.task_id === task.task_id);
    const previousState = dbRecord ? dbRecord.current_state : "NEW";

    // 3. Calculate the Burn Rate
    let percent = 0;
    if (task.budget_hours > 0) {
        percent = (task.tracked_hours / task.budget_hours) * 100;
    }

    // 4. The State Machine Logic
    let newState = "HEALTHY";
    if (percent >= 100) newState = "CRITICAL";
    else if (percent >= 80) newState = "WARNING";

    // 5. The Delta Gate (Should we alert the CEO/Manager?)
    // We ONLY alert if the state has CHANGED and it is NOT healthy.
    let requiresAlert = false;
    if (newState !== previousState && newState !== "HEALTHY") {
        requiresAlert = true; 
    }

    // 6. Output the final decision payload
    results.push({
        json: {
            task_id: task.task_id,
            task_name: task.task_name,
            budget_hours: task.budget_hours,
            tracked_hours: task.tracked_hours,
            burn_percent: parseFloat(percent.toFixed(1)),
            previous_state: previousState,
            new_state: newState,
            requires_alert: requiresAlert
        }
    });
}

return results;

